    60→#[test]
    61→fn jjtfu_no_options_error() {
    62→    let mut gallops = make_valid_gallops();
    63→    let (heat_key, heat) = make_valid_heat("AB", "my-heat", jjrg_HeatStatus::Stabled);
    64→    gallops.heats.insert(heat_key, heat);
    65→
    66→    let args = jjrg_FurloughArgs {
    67→        firemark: "AB".to_string(),
    68→        racing: false,
    69→        stabled: false,
    70→        silks: None,
    71→    };
    72→
    73→    let result = gallops.jjrg_furlough(args);
    74→    assert!(result.is_err());
    75→    assert!(result.unwrap_err().contains("At least one option required"));
    76→}
