   595→#[test]
   596→fn jjtg_slate_with_before_inserts_at_position() {
   597→    let mut gallops = make_valid_gallops();
   598→    let (heat_key, mut heat) = make_valid_heat("AB", "my-heat");
   599→
   600→    // Add a second pace
   601→    let pace2_key = "₢ABAAB".to_string();
   602→    let pace2 = jjrg_Pace {
   603→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "second-pace", None)],
   604→    };
   605→    heat.paces.insert(pace2_key.clone(), pace2);
   606→    heat.order.push(pace2_key.clone());
   607→    heat.next_pace_seed = "AAC".to_string();
   608→
   609→    let first_pace = heat.order[0].clone();
   610→    gallops.heats.insert(heat_key.clone(), heat);
   611→
   612→    // Insert before the second pace
   613→    let args = jjrg_SlateArgs {
   614→        firemark: "AB".to_string(),
   615→        silks: "inserted-pace".to_string(),
   616→        text: "Insert before second".to_string(),
   617→        before: Some(pace2_key.clone()),
   618→        after: None,
   619→        first: false,
   620→    };
   621→
   622→    let result = gallops.jjrg_slate(args).unwrap();
   623→
   624→    let heat = gallops.heats.get(&heat_key).unwrap();
