     5→//! Tests for jjx_garland command
     6→//!
     7→//! Tests the garland operation which celebrates heat completion and creates
     8→//! a continuation heat.
     9→
    10→use super::jjro_ops::jjrg_garland;
    11→use super::jjrt_types::{jjrg_PaceState, jjrg_HeatStatus, jjrg_Tack, jjrg_Pace, jjrg_Heat, jjrg_Gallops, jjrg_GarlandArgs, JJRG_UNKNOWN_BASIS};
    12→use super::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
    13→use std::collections::BTreeMap;
    14→use indexmap::IndexMap;
    15→
    16→// Helper to create a minimal valid Gallops structure
    17→// Sets next_heat_seed to "AC" so that manually-created "AB" heat doesn't conflict
    18→fn make_valid_gallops() -> jjrg_Gallops {
    19→    jjrg_Gallops {
    20→        next_heat_seed: "AC".to_string(),
    21→        heats: IndexMap::new(),
    22→    }
    23→}
    24→
    25→// Helper to create a valid Tack
    26→fn make_valid_tack(state: jjrg_PaceState, silks: &str, direction: Option<String>) -> jjrg_Tack {
    27→    jjrg_Tack {
    28→        ts: "260101-1200".to_string(),
    29→        state,
    30→        text: "Test tack text".to_string(),
    31→        silks: silks.to_string(),
    32→        basis: JJRG_UNKNOWN_BASIS.to_string(),
    33→        direction,
    34→    }
    35→}
    36→
    37→// Helper to create a valid Heat with multiple paces
    38→fn make_heat_with_paces(heat_id: &str, silks: &str, pace_states: Vec<jjrg_PaceState>) -> (String, jjrg_Heat) {
    39→    let heat_key = format!("₣{}", heat_id);
    40→    let mut paces = BTreeMap::new();
    41→    let mut order = Vec::new();
    42→
    43→    for (idx, state) in pace_states.iter().enumerate() {
    44→        let pace_key = format!("₢{}AA{}", heat_id, char::from(b'A' + idx as u8));
    45→        let pace_silks = format!("pace-{}", idx);
    46→        let pace = jjrg_Pace {
    47→            tacks: vec![make_valid_tack(state.clone(), &pace_silks, None)],
    48→        };
    49→        paces.insert(pace_key.clone(), pace);
    50→        order.push(pace_key);
    51→    }
    52→
    53→    // Calculate next seed
    54→    let next_char = char::from(b'A' + pace_states.len() as u8);
    55→    let next_pace_seed = format!("AA{}", next_char);
    56→
    57→    let heat = jjrg_Heat {
    58→        silks: silks.to_string(),
    59→        creation_time: "260101".to_string(),
    60→        status: jjrg_HeatStatus::Racing,
    61→        order,
    62→        next_pace_seed,
    63→        paddock_file: format!(".claude/jjm/jjp_{}.md", heat_id),
    64→        paces,
    65→    };
    66→    (heat_key, heat)
    67→}
