   123→    let _ = std::fs::remove_dir_all(&temp_dir);
   124→    std::fs::create_dir_all(&temp_dir).unwrap();
   125→
   126→    // Create heat with mixed paces: 2 complete, 2 rough
   127→    let (heat_key, heat) = make_heat_with_paces(
   128→        "AB",
   129→        "test-heat",
   130→        vec![
   131→            jjrg_PaceState::Complete,
   132→            jjrg_PaceState::Complete,
   133→            jjrg_PaceState::Rough,
   134→            jjrg_PaceState::Rough,
   135→        ],
   136→    );
   137→
   138→    // Create paddock file
   139→    let paddock_path = temp_dir.join(&heat.paddock_file);
   140→    std::fs::create_dir_all(paddock_path.parent().unwrap()).unwrap();
   141→    std::fs::write(&paddock_path, "Original paddock content\n\nMore details here.").unwrap();
   142→
   143→    gallops.heats.insert(heat_key.clone(), heat);
   144→
   145→    let args = jjrg_GarlandArgs {
   146→        firemark: "AB".to_string(),
   147→    };
   148→
   149→    let result = jjrg_garland(&mut gallops, args, &temp_dir).unwrap();
   150→
   151→    // Verify result structure
   152→    assert_eq!(result.old_firemark, "₣AB");
   153→    assert_eq!(result.old_silks, "garlanded-test-heat-01");
   154→    assert!(result.new_firemark.starts_with('₣'));
   155→    assert_eq!(result.new_silks, "test-heat-02");
   156→    assert_eq!(result.paces_transferred, 2);
   157→    assert_eq!(result.paces_retained, 2);
   158→
   159→    // Verify old heat was updated (same firemark, but silks/status changed)
   160→    let old_heat = gallops.heats.get("₣AB").unwrap();
   161→    assert_eq!(old_heat.silks, "garlanded-test-heat-01");
   162→    assert_eq!(old_heat.status, jjrg_HeatStatus::Stabled);
   163→    // After drafting to new heat, old heat retains only complete/abandoned paces
   164→    assert_eq!(old_heat.paces.len(), 2); // Only retained paces
   165→
   166→    // Verify new heat was created
   167→    let new_heat = gallops.heats.get(&result.new_firemark).unwrap();
   168→    assert_eq!(new_heat.silks, "test-heat-02");
   169→    assert_eq!(new_heat.status, jjrg_HeatStatus::Racing);
   170→    assert_eq!(new_heat.paces.len(), 2); // Only transferred paces
   171→
   172→    // Verify new heat is at front of heats map
   173→    let first_key = gallops.heats.keys().next().unwrap();
   174→    assert_eq!(first_key, &result.new_firemark);
   175→
   176→    // Verify paddock marker was added to old heat
   177→    let old_paddock_content = std::fs::read_to_string(temp_dir.join(&old_heat.paddock_file)).unwrap();
   178→    assert!(old_paddock_content.contains("Garlanded at pace 2"));
   179→
   180→    // Verify paddock content was copied to new heat (without marker)
   181→    let new_paddock_content = std::fs::read_to_string(temp_dir.join(&new_heat.paddock_file)).unwrap();
   182→    assert!(new_paddock_content.contains("Original paddock content"));
   183→    assert!(!new_paddock_content.contains("Garlanded at pace"));
   184→
   185→    let _ = std::fs::remove_dir_all(&temp_dir);
   186→}
