   330→        if let Some(pace) = heat.paces.get(*coronet_key) {
   331→            if let Some(tack) = pace.tacks.first() {
   332→                return tack.state == PaceState::Rough;
   333→            }
   334→        }
   335→        false
   336→    }).collect();
   337→
   338→    assert_eq!(rough.len(), 1);
   339→    assert_eq!(rough[0], "₢ACAAB");
   340→}
