    19→fn make_valid_tack(state: jjrg_PaceState, silks: &str, direction: Option<String>) -> jjrg_Tack {
    20→    jjrg_Tack {
    21→        ts: "260101-1200".to_string(),
    22→        state,
    23→        text: "Test tack text".to_string(),
    24→        silks: silks.to_string(),
    25→        basis: JJRG_UNKNOWN_BASIS.to_string(),
    26→        direction,
    27→    }
    28→}
