    30→fn make_heat_with_paces(heat_id: &str, silks: &str, pace_count: usize) -> (String, jjrg_Heat) {
    31→    use std::collections::BTreeMap;
    32→
    33→    let heat_key = format!("₣{}", heat_id);
    34→    let mut paces = BTreeMap::new();
    35→    let mut order = Vec::new();
    36→
    37→    for i in 0..pace_count {
    38→        // Generate coronet: AAA, AAB, AAC, etc.
    39→        let pace_suffix = format!("AA{}", (b'A' + i as u8) as char);
    40→        let pace_key = format!("₢{}{}", heat_id, pace_suffix);
    41→        let pace_silks = format!("pace-{}", i + 1);
    42→
    43→        let pace = jjrg_Pace {
    44→            tacks: vec![make_valid_tack(jjrg_PaceState::Rough, &pace_silks, None)],
    45→        };
    46→
    47→        order.push(pace_key.clone());
    48→        paces.insert(pace_key, pace);
    49→    }
    50→
    51→    let next_pace_suffix = format!("AA{}", (b'A' + pace_count as u8) as char);
    52→
    53→    let heat = jjrg_Heat {
    54→        silks: silks.to_string(),
    55→        creation_time: "260101".to_string(),
    56→        status: jjrg_HeatStatus::Racing,
    57→        order,
    58→        next_pace_seed: next_pace_suffix,
    59→        paddock_file: format!(".claude/jjm/jjp_{}.md", heat_id),
    60→        paces,
    61→    };
    62→
    63→    (heat_key, heat)
    64→}
