    29→/// Handler for jjx_nominate command
    30→pub fn jjrx_run_nominate(args: jjrx_NominateArgs) -> i32 {
    31→    use std::path::Path;
    32→
    33→    // Acquire lock FIRST - fail fast if another operation is in progress
    34→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
    35→        Ok(l) => l,
    36→        Err(e) => {
    37→            eprintln!("jjx_nominate: error: {}", e);
    38→            return 1;
    39→        }
    40→    };
    41→
    42→    let mut gallops = if args.file.exists() {
    43→        match Gallops::jjrg_load(&args.file) {
    44→            Ok(g) => g,
    45→            Err(e) => {
    46→                eprintln!("jjx_nominate: error loading Gallops: {}", e);
    47→                return 1;
    48→            }
    49→        }
    50→    } else {
    51→        if let Some(parent) = args.file.parent() {
    52→            if let Err(e) = std::fs::create_dir_all(parent) {
    53→                eprintln!("jjx_nominate: error creating directory: {}", e);
    54→                return 1;
    55→            }
    56→        }
    57→        Gallops {
    58→            next_heat_seed: "AA".to_string(),
    59→            heats: IndexMap::new(),
    60→        }
    61→    };
    62→
    63→    let base_path = args.file.parent()
    64→        .and_then(|p| p.parent())
    65→        .and_then(|p| p.parent())
    66→        .unwrap_or(Path::new("."));
    67→
    68→    let silks = args.silks.clone();
    69→    let nominate_args = LibNominateArgs {
    70→        silks: args.silks,
    71→        created: jjrc_timestamp_from_env(),
    72→    };
    73→
    74→    match gallops.jjrg_nominate(nominate_args, base_path) {
    75→        Ok(result) => {
    76→            let fm = Firemark::jjrf_parse(&result.firemark).expect("nominate returned invalid firemark");
    77→            let message = format_heat_message(&fm, HeatAction::Nominate, &silks);
    78→
    79→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
    80→                Ok(hash) => {
    81→                    eprintln!("jjx_nominate: committed {}", &hash[..8]);
    82→                }
    83→                Err(e) => {
    84→                    eprintln!("jjx_nominate: error: {}", e);
    85→                    return 1;
    86→                }
    87→            }
    88→
    89→            println!("{}", result.firemark);
